#include <pthread.h>
#include <stdlib.h>
#include <string.h>
#include "sat.h"

/* Sequential generation: explores all combinations for x[i..n-1]
   and returns the count. Modifies x in place. */
static long gen_seq(int x[], int i, int n, BoolFun f) {
    if (i == n) {
        return f(x);
    }
    x[i] = 0;
    long r0 = gen_seq(x, i + 1, n, f);
    x[i] = 1;
    long r1 = gen_seq(x, i + 1, n, f);
    return r0 + r1;
}

/* Structure for passing arguments to parallel threads */
typedef struct {
    int *x;
    int i;
    int n;
    BoolFun f;
    int p;
} ThreadArg;

/* Forward declaration */
static void *thread_func(void *arg);

/* Parallel generation with recursive thread creation.
   For i < p, creates a child thread for x[i]=1 and handles x[i]=0
   in the current thread. For i >= p, falls back to sequential. */
static long gen_work(int x[], int i, int n, BoolFun f, int p) {
    if (i == n) {
        return f(x);
    }
    if (i >= p) {
        return gen_seq(x, i, n, f);
    }

    /* i < p: create a thread for x[i]=1 */
    int *child_x = malloc(n * sizeof(int));
    memcpy(child_x, x, n * sizeof(int));
    child_x[i] = 1;

    ThreadArg *ta = malloc(sizeof(ThreadArg));
    ta->x = child_x;
    ta->i = i + 1;
    ta->n = n;
    ta->f = f;
    ta->p = p;

    pthread_t thread;
    pthread_create(&thread, NULL, thread_func, ta);

    /* Handle x[i]=0 in this thread */
    x[i] = 0;
    long r0 = gen_work(x, i + 1, n, f, p);

    /* Wait for child thread */
    void *r1_ptr;
    pthread_join(thread, &r1_ptr);
    long r1 = (long)r1_ptr;

    return r0 + r1;
}

/* Thread function wrapper: receives ownership of x and ThreadArg,
   frees them after work completes */
static void *thread_func(void *arg) {
    ThreadArg *ta = (ThreadArg *)arg;
    long result = gen_work(ta->x, ta->i, ta->n, ta->f, ta->p);
    free(ta->x);
    free(ta);
    return (void *)result;
}

/* Public function: counts the number of true evaluations of f
   over all 2^n input combinations using 2^p threads */
int recuento(int n, BoolFun f, int p) {
    int *x = malloc(n * sizeof(int));
    long result = gen_work(x, 0, n, f, p);
    free(x);
    return (int)result;
}
